    }
    max_profit = original_profit;

    // Try modifying each possible window of size k
    for i in 0..(n - k + 1) {
        let mut profit_change = 0;
        let half = k / 2;
        for j in i..i + k {
            if j < i + half {
                // Original strategy was something else, now it's 0 (hold)
                profit_change -= strategy[j as usize] * prices[j as usize];
            } else {
                // Original strategy was something else, now it's 1 (sell)
                profit_change += strategy[j as usize] * prices[j as usize];
            }
        }
        // Update max_profit if this modification gives a higher profit
        let current_profit = original_profit + profit_change;
        max_profit = std::cmp::max(max_profit, current_profit);
    }

    max_profit
}
